static void flushed_printf(const char* format, ...) {
  va_list args;
  va_start(args, format);
  vprintf(format, args);
  va_end(args);
  fflush(stdout);
}

static void show_progress_init(int length) {
  flushed_printf("[");
  for (int i = 0; length > i; i++)
    flushed_printf(" ");
  flushed_printf("]");
  for (int i = 0; i <= length; i++)
    flushed_printf("\b");
}

static void show_progress_step(int domove, char newchar) {
  flushed_printf("%c", newchar);
  if (!domove)
    flushed_printf("\b");
}

static void show_progress_done(void) {
  flushed_printf("\n");
}

template <typename F>
double benchmark(int iterations, F func) {
    double total = 0.0;
    for (int i = 0; i < iterations; i++) {
        total += func();
    }
    return total / iterations;
}

static double getElapsedtime(std::chrono::steady_clock::time_point start) {
    auto end = std::chrono::steady_clock::now();
    std::chrono::duration<double, std::milli> elapsed = end - start;
    return elapsed.count();
}

